import { useApp } from "../context/AppContext";

export default function RecipeCard({ recipe }) {
const { dispatch } = useApp();

const addToPlanner = () => {
dispatch({
type: "ADD_TO_PLANNER",
payload: {
day: "Monday",
mealType: "Lunch",
recipe
}
});
};

return (
<div style={{ border: "1px solid #ccc", padding: 10 }}> <h4>{recipe.name}</h4> <p>{recipe.calories} kcal</p> <p>Protein: {recipe.protein}g</p>


  <button onClick={addToPlanner}>
    Add to Planner
  </button>
</div>


);
}
